// Define a function to fix broken HTML tags
function fixHtmlTags(s) {
  let tags = [];
  let result = '';
  for (let i = 0; i < s.length; i++) {
    if (s[i] === '<') {
      if (s[i + 1] === '/') {
        tags.pop();
      } else {
        tags.push(s[i + 1]);
      }
    }
    result += s[i];
  }
  // Re-add missing closing tags
  for (let tag of tags) {
    result += '</' + tag + '>
';
  }
  return result;
}

