class Solution:
  def fixHtmlTags(self, s):
    tags = []
    result = ''
    for i in range(len(s)):
      if s[i] == '<':
        if s[i + 1] == '/':
          tags.pop()
        else:
          tags.append(s[i + 1])
      result += s[i]
    # Re-add missing closing tags
    for tag in tags:
      result += '</' + tag + '>
'
    return result
